```go
type RequestVoteArgs struct {
    Term         int // 候选人的 term
    CandidateId  int // 候选人的 me
    LastLogIndex int // 候选人最后一条日志的 Index
    LastLogTerm  int // 候选人最后一条日志的 Term
}

type RequestVoteReply struct {
    Term        int  // 返回自己的 currentTerm，让候选人更新
    VoteGranted bool // 是否同意投票
}

func (rf *Raft) RequestVote(args *RequestVoteArgs, reply *RequestVoteReply) {
    rf.mu.Lock()
    defer rf.mu.Unlock()

    reply.Term = rf.currentTerm
    reply.VoteGranted = false

    // Rule 1: 如果对方 term 更小，直接拒绝
    if args.Term < rf.currentTerm {
        return
    }

    // Rule 2: 如果对方 term 更大，立刻退回 Follower 并更新 term
    // 注意：这里必须先更新 term 再判断投票，否则可能用旧 term 的 votedFor 做判断
    if args.Term > rf.currentTerm {
        rf.currentTerm = args.Term
        rf.votedFor = -1
        rf.state = Follower
        rf.persist() // 更新了持久化状态，必须立刻落盘
    }

    // Rule 3: 检查是否可以投票（两个条件都要满足）
    // 条件 A: 本 term 还没投过票，或者已经投给了这个候选人（幂等）
    canVote := rf.votedFor == -1 || rf.votedFor == args.CandidateId

    // 条件 B: 候选人的日志至少和自己一样新
    // 「一样新」的定义：先比最后一条日志的 term，term 相同再比 index
    lastLogIndex := len(rf.log) - 1
    lastLogTerm := rf.log[lastLogIndex].Term
    logUpToDate := args.LastLogTerm > lastLogTerm ||
        (args.LastLogTerm == lastLogTerm && args.LastLogIndex >= lastLogIndex)

    if canVote && logUpToDate {
        rf.votedFor = args.CandidateId
        rf.persist()
        rf.resetElectionTimer() // 投票后重置选举超时，避免立刻发起新选举
        reply.VoteGranted = true
    }
}
```

「日志至少一样新」这个检查是 Raft 安全性的核心保证之一（Figure 3 中的 Leader Completeness Property）。直觉是：如果一个 Candidate 的日志不如自己新，说明它可能丢失了某些已提交的条目，投票给它可能导致数据丢失。先比 term 再比 index 的规则来自这样的推理：term 更高意味着它在更晚的 term 里参与了复制，大概率拥有更完整的日志；term 相同时 index 更大才是真的「更新」。

### 日志复制：AppendEntries RPC

AppendEntries 既是心跳（entries 为空时）又是日志复制，处理逻辑比 RequestVote 复杂得多：

```go
type AppendEntriesArgs struct {
    Term         int        // Leader 的 term
    LeaderId     int        // 用于 Follower 重定向客户端
    PrevLogIndex int        // 新日志紧前面那条的 Index
    PrevLogTerm  int        // 新日志紧前面那条的 Term
    Entries      []LogEntry // 要复制的日志条目（心跳时为空）
    LeaderCommit int        // Leader 的 commitIndex
}

type AppendEntriesReply struct {
    Term    int  // 自己的 currentTerm
    Success bool // 一致性检查是否通过
    // 用于快速回退的优化字段（XTerm/XIndex 优化）
    XTerm  int  // 冲突条目的 term（-1 表示 PrevLogIndex 越界）
    XIndex int  // XTerm 对应的第一条日志的 Index
    XLen   int  // Follower 的日志长度（当 XTerm=-1 时使用）
}

func (rf *Raft) AppendEntries(args *AppendEntriesArgs, reply *AppendEntriesReply) {
    rf.mu.Lock()
    defer rf.mu.Unlock()

    reply.Term = rf.currentTerm
    reply.Success = false

    // Rule 1: 拒绝过时的 Leader
    if args.Term < rf.currentTerm {
        return
    }

    // 收到合法 Leader 的消息，退回 Follower 并重置选举超时
    rf.currentTerm = args.Term
    rf.state = Follower
    rf.resetElectionTimer()
    if args.Term > rf.currentTerm || rf.votedFor != args.LeaderId {
        rf.votedFor = -1 // term 变化时清空投票记录
        rf.persist()
    }

    // Rule 2: 一致性检查——PrevLogIndex 位置的 term 必须匹配
    if args.PrevLogIndex >= len(rf.log) {
        // PrevLogIndex 超出了我的日志范围，告知 Leader 我的日志有多长
        reply.XTerm = -1
        reply.XLen = len(rf.log)
        return
    }
    if rf.log[args.PrevLogIndex].Term != args.PrevLogTerm {
        // 该位置的 term 不匹配，告知冲突 term 和该 term 的起始位置
        // Leader 可以直接跳过整个冲突 term，而不是逐条递减
        reply.XTerm = rf.log[args.PrevLogIndex].Term
        reply.XIndex = args.PrevLogIndex
        for reply.XIndex > 0 && rf.log[reply.XIndex-1].Term == reply.XTerm {
            reply.XIndex--
        }
        return
    }

    // Rule 3: 追加新条目，处理冲突
    // 注意：不能直接截断再追加！要逐条比较，找到第一个冲突点再截断
    // 原因：AppendEntries 可能乱序到达，直接截断会删掉已提交的日志
    for i, entry := range args.Entries {
        idx := args.PrevLogIndex + 1 + i
        if idx < len(rf.log) {
            if rf.log[idx].Term != entry.Term {
                // 发现冲突，截断冲突点及之后的所有条目
                rf.log = rf.log[:idx]
                rf.log = append(rf.log, args.Entries[i:]...)
                break
            }
            // term 匹配，这条日志已经有了，跳过
        } else {
            // 追加新条目
            rf.log = append(rf.log, args.Entries[i:]...)
            break
        }
    }
    rf.persist()

    // Rule 4: 更新 commitIndex
    if args.LeaderCommit > rf.commitIndex {
        // 取 LeaderCommit 和自己日志末尾的较小值，避免越界
        rf.commitIndex = min(args.LeaderCommit, len(rf.log)-1)
        rf.notifyApplier() // 通知 applier goroutine 有新条目可以应用了
    }

    reply.Success = true
}
```

这里最容易出 bug 的地方是 Rule 3 的日志追加逻辑。初学者往往写 `rf.log = append(rf.log[:args.PrevLogIndex+1], args.Entries...)` 看起来简洁，但在网络乱序场景下会出问题：假设 AppendEntries(index=1~5) 和 AppendEntries(index=1~3) 乱序到达，后者后到，它会把已经写入的 index 4、5 截掉，即使那两条可能已经被提交了。正确做法是逐条比较，找到第一个 term 不匹配的位置才截断。

### Leader 的复制循环

Leader 当选后为每个 peer 启动一个独立的 goroutine 做日志复制：

```go
func (rf *Raft) becomeLeader() {
    rf.state = Leader
    // 初始化 volatile leader state
    // nextIndex 初始化为 Leader 最后一条日志的下一个位置（乐观估计）
    // matchIndex 初始化为 0（保守，什么都没确认）
    for i := range rf.peers {
        rf.nextIndex[i] = len(rf.log) // 即 lastLogIndex + 1
        rf.matchIndex[i] = 0
    }
    // 立刻发一次心跳，防止其他节点重新选举
    rf.broadcastHeartbeat()
}

func (rf *Raft) replicateToFollower(peer int) {
    rf.mu.Lock()
    if rf.state != Leader {
        rf.mu.Unlock()
        return
    }

    nextIdx := rf.nextIndex[peer]
    prevLogIndex := nextIdx - 1
    prevLogTerm := rf.log[prevLogIndex].Term

    // 构造要发送的日志片段（可能为空，即心跳）
    entries := make([]LogEntry, len(rf.log)-nextIdx)
    copy(entries, rf.log[nextIdx:])

    args := &AppendEntriesArgs{
        Term:         rf.currentTerm,
        LeaderId:     rf.me,
        PrevLogIndex: prevLogIndex,
        PrevLogTerm:  prevLogTerm,
        Entries:      entries,
        LeaderCommit: rf.commitIndex,
    }
    rf.mu.Unlock()
    // ！！注意：发送 RPC 时绝对不能持锁！！
    // 持锁发 RPC 是 Raft 实现中最常见的死锁原因

    reply := &AppendEntriesReply{}
    ok := rf.sendAppendEntries(peer, args, reply)

    rf.mu.Lock()
    defer rf.mu.Unlock()

    if !ok || rf.state != Leader || args.Term != rf.currentTerm {
        // RPC 失败，或者我已经不是 Leader 了，或者 term 已经变了
        // term 变化意味着这次 RPC 的结果已经过时，直接丢弃
        return
    }

    if reply.Term > rf.currentTerm {
        // 发现更高 term，退回 Follower
        rf.currentTerm = reply.Term
        rf.votedFor = -1
        rf.state = Follower
        rf.persist()
        return
    }

    if reply.Success {
        // 更新 matchIndex 和 nextIndex
        // 注意：要取 max 而不是直接赋值！原因是 RPC 可能乱序返回
        newMatchIndex := args.PrevLogIndex + len(args.Entries)
        if newMatchIndex > rf.matchIndex[peer] {
            rf.matchIndex[peer] = newMatchIndex
        }
        rf.nextIndex[peer] = rf.matchIndex[peer] + 1

        // 检查是否可以推进 commitIndex
        // 找到一个 N，使得多数节点的 matchIndex >= N，且 log[N].Term == currentTerm
        // 「且 log[N].Term == currentTerm」这个条件是 Figure 8 安全性的关键！
        for n := len(rf.log) - 1; n > rf.commitIndex; n-- {
            if rf.log[n].Term != rf.currentTerm {
                // Raft 不能提交之前 term 的日志，只能通过提交当前 term 的日志间接提交
                continue
            }
            count := 1 // 算上自己
            for i := range rf.peers {
                if i != rf.me && rf.matchIndex[i] >= n {
                    count++
                }
            }
            if count > len(rf.peers)/2 {
                rf.commitIndex = n
                rf.notifyApplier()
                break // 找到最大可提交的 N 即可退出
            }
        }
    } else {
        // 一致性检查失败，使用 XTerm/XIndex 快速回退
        if reply.XTerm == -1 {
            // Follower 日志太短，直接设置 nextIndex 为 Follower 的日志长度
            rf.nextIndex[peer] = reply.XLen
        } else {
            // 在 Leader 日志中查找 XTerm 的最后一条
            found := false
            for i := len(rf.log) - 1; i > 0; i-- {
                if rf.log[i].Term == reply.XTerm {
                    // Leader 有这个 term 的日志，从 Leader 的该 term 最后一条之后开始
                    rf.nextIndex[peer] = i + 1
                    found = true
                    break
                }
            }
            if !found {
                // Leader 没有 XTerm，跳到 Follower 该 term 的起始位置
                rf.nextIndex[peer] = reply.XIndex
            }
        }
    }
}
```

### Election Timer 的设计

选举超时是 Raft 活性（liveness）的关键。超时时间必须随机化，否则多个 Follower 会同时超时、同时发起选举，导致选票瓜分（split vote）死循环：

```go
const (
    electionTimeoutBase  = 150 * time.Millisecond
    electionTimeoutRange = 150 * time.Millisecond // 随机范围：150ms ~ 300ms
    heartbeatInterval    = 50 * time.Millisecond  // 心跳间隔要远小于选举超时
)

func (rf *Raft) resetElectionTimer() {
    // 每次收到合法 Leader 心跳、投票给某人时调用
    timeout := electionTimeoutBase + time.Duration(rand.Int63n(int64(electionTimeoutRange)))
    rf.electionTimer.Reset(timeout)
}

func (rf *Raft) ticker() {
    for {
        select {
        case <-rf.electionTimer.C:
            rf.mu.Lock()
            if rf.state != Leader {
                rf.startElection() // 超时后发起选举
            }
            rf.resetElectionTimer()
            rf.mu.Unlock()
        case <-rf.heartbeatTimer.C:
            rf.mu.Lock()
            if rf.state == Leader {
                rf.broadcastHeartbeat()
            }
            rf.heartbeatTimer.Reset(heartbeatInterval)
            rf.mu.Unlock()
        }
    }
}
```

## 第四步：扩展延伸——从能跑起来到工业级

### 锁的设计：持锁发 RPC 是死锁炸弹

Raft 实现里最经典的死锁场景：节点 A 持着 mu 锁，正在给节点 B 发 RequestVote RPC；节点 B 正在处理节点 A 的另一个 RPC，需要获取 A 的 mu 锁来做回调……两者互等，系统卡死。正确做法是「在加锁区域内只做状态读取，在释放锁后才发 RPC，收到回复后重新加锁做状态更新，并且必须验证 term 没有变化」。这个模式叫「先读状态，释放锁，发 RPC，重新加锁，校验状态，更新状态」，MIT 6.824 的 Guidance 文档里对这个模式有详细说明。

### 持久化的最小集合

Raft 论文明确指出只有三个字段需要持久化：`currentTerm`、`votedFor`、`log`。其他字段要么可以从这三个推导出来（`commitIndex`、`lastApplied` 可以从 0 开始重建），要么本身就是 Leader 重新初始化的（`nextIndex`、`matchIndex`）。`currentTerm` 和 `votedFor` 持久化是为了保证在同一个 term 内只投一票，即使节点重启也不违反「每个 term 最多一个 Leader」的不变量。`log` 持久化是显然的，日志就是状态机的真相来源。

### 快速日志回退：XTerm/XIndex 优化

基础实现中 Leader 每次 AppendEntries 失败就把 `nextIndex[peer]--`，如果 Follower 的日志落后 1000 条，就需要 1000 次 RPC 才能对齐，性能极差。XTerm/XIndex 优化让 Follower 在失败响应中携带冲突 term 的起始位置，Leader 可以直接跳过整个冲突 term，大幅减少 RPC 次数。etcd/raft 的实现更进一步，用 `MsgAppResp` 的 `RejectHint` 字段直接返回建议的 nextIndex。

### MIT 6.824 中的高频 Bug

做过 6.824 Lab2 的人都踩过这几个坑。第一是 apply 乱序：`applyCh` 是 buffered channel，如果在持锁时向 channel 发消息，channel 满了会阻塞，导致死锁；正确做法是用单独的 applier goroutine 处理提交，通过条件变量（`sync.Cond`）唤醒。第二是重复 apply：节点重启后 `lastApplied` 从 0 开始，但 `commitIndex` 可能已经很高了，applier 会把所有日志重新 apply 一遍，如果状态机不做幂等处理会出问题。第三是 Figure 8 陷阱：忘记检查 `log[N].Term == currentTerm` 就推进 commitIndex，会导致已提交条目被覆盖，这是最难排查的 safety violation。
